+    } else {
+      expanded = n->as_StoreFlat()->expand_non_atomic(igvn);
+    }
+    if (expanded) {
+      sfn_worklist.remove(n->as_SafePoint());
+      igvn.C->remove_flat_access(n);
+    }
+  });
